		})
	}
	defer resp.Body.Close()

	// Read entire response body to avoid connection leaks
	_, _ = io.Copy(io.Discard, resp.Body)

	// Check if webhook responded with a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook returned non-success status: " + resp.Status,
