// WebhookRequest represents the incoming POST request body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response returned by the handler
type WebhookResponse struct {
	Success  bool   `json:"success"`
	Message  string `json:"message"`
	SavedURL string `json:"saved_url,omitempty"`
}

// currentWebhookURL stores the saved webhook configuration in memory
var currentWebhookURL string

// ConfigureWebhook handles webhook configuration and validation
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Validate the response status code is in the 2xx range
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the valid webhook configuration
	currentWebhookURL = req.WebhookURL

	// Return success response
	return ctx.JSON(WebhookResponse{
		Success:  true,
		Message:  "Webhook URL configured successfully",
		SavedURL: currentWebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

