// isPrivateIP checks if an IP address is in a private or reserved range
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check private IPv4 ranges
	privateIPv4 := []net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		{IP: net.ParseIP("100.64.0.0"), Mask: net.CIDRMask(10, 32)}, // Carrier-grade NAT
	}
	for _, cidr := range privateIPv4 {
		if cidr.Contains(ip) {
			return true
		}
	}

	// Check private IPv6 ranges
	privateIPv6 := []net.IPNet{
		{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)}, // Unique Local Addresses
		{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)}, // Link-Local Addresses
	}
	for _, cidr := range privateIPv6 {
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

// validateHostAgainstSSRF checks if a hostname resolves to any private/reserved IP addresses
func validateHostAgainstSSRF(hostname string) error {
	ips, err := net.LookupHost(hostname)
	if err != nil {
		return err
	}

	for _, ipStr := range ips {
		ip := net.ParseIP(ipStr)
		if isPrivateIP(ip) {
			return fiber.NewError(fiber.StatusBadRequest, "Webhook URL points to a private or reserved IP address")
		}
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Validate hostname does not resolve to private IP (SSRF protection)
	if err := validateHostAgainstSSRF(parsedURL.Hostname()); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   err.Error(),
		})
	}

	// Create a secure HTTP client with strict timeouts and redirect validation
	transport := &http.Transport{
		DialContext: (&net.Dialer{
			Timeout:   2 * time.Second,   // Connection timeout
			KeepAlive: 30 * time.Second,
		}).DialContext,
		TLSHandshakeTimeout: 2 * time.Second, // TLS handshake timeout
		DisableKeepAlives:   true,           // Prevent reuse of connections to untrusted hosts
	}

	client := &http.Client{
		Timeout:   3 * time.Second, // Total request timeout
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirects to prevent infinite loops
			if len(via) >= 3 {
				return http.ErrUseLastResponse
			}

			// Validate redirect URL does not point to private IP
			if err := validateHostAgainstSSRF(req.URL.Hostname()); err != nil {
				return err
			}

			return nil
		},
	}

	// Send GET test request to webhook URL (as per requirement)
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to connect to webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded with a success status (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the configuration (assume db is a predefined database instance)
