)

// AppConfig stores the application's webhook configuration with thread-safe access
type AppConfig struct {
	WebhookURL string
	mu         sync.RWMutex
}

var config AppConfig

// WebhookConfigRequest represents the JSON body for configuring the webhook
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to set and validate the webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to parse request: " + err.Error(),
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid URL format: " + err.Error(),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Validation request failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save configuration with thread-safe access
	config.mu.Lock()
	config.WebhookURL = req.WebhookURL
	config.mu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook URL configured and validated successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

