package main

import (
	"fmt"
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variables to store webhook configuration with thread safety
var (
	currentWebhookURL string
	configMutex       sync.RWMutex
)

// WebhookConfigRequest represents the incoming request structure
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// APIResponse represents the standard JSON response structure
type APIResponse struct {
	Status  string      `json:"status"`
	Message string      `json:"message"`
	Data    interface{} `json:"data,omitempty"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: fmt.Sprintf("Failed to parse request: %v", err),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: fmt.Sprintf("Invalid URL format: %v", err),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: fmt.Sprintf("Test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check for successful response status (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(APIResponse{
			Status:  "error",
			Message: fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration with thread safety
	configMutex.Lock()
	currentWebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.JSON(APIResponse{
		Status:  "success",
		Message: "Webhook configured successfully",
		Data: map[string]string{
			"webhook_url": req.WebhookURL,
		},
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

