// isRestrictedIP checks if an IP address falls into restricted ranges (SSRF protection)
func isRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check loopback addresses
	if loopbackIPv4.Contains(ip) || loopbackIPv6.Contains(ip) {
		return true
	}

	// Check private network ranges
	if privateIPv41.Contains(ip) || privateIPv42.Contains(ip) || privateIPv43.Contains(ip) || privateIPv6.Contains(ip) {
