)

// WebhookConfigRequest represents the incoming POST request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response returned by the handler
type WebhookResponse struct {
	Status     string `json:"status"`
	Message    string `json:"message,omitempty"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

// WebhookConfig stores the current saved webhook configuration
type WebhookConfig struct {
	WebhookURL string
}

var (
	currentConfig WebhookConfig
	configMutex   sync.RWMutex // Mutex to ensure thread-safe access to config
)

// ConfigureWebhook handles POST requests to set and validate webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	// Validate webhook URL is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "webhook_url is a required field",
		})
	}

	// Validate URL format and scheme (http/https)
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: fmt.Sprintf("Invalid URL format: %v", err),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout for validation request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Status:  "error",
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Prepare success message with response status
	validationMsg := fmt.Sprintf(
		"Webhook URL validated successfully. Response status: %d %s",
		resp.StatusCode,
		resp.Status,
	)

	// Save the validated configuration with thread-safe access
	configMutex.Lock()
	currentConfig.WebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Status:     "success",
		Message:    validationMsg,
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define API routes
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: GET endpoint to retrieve current webhook configuration
	app.Get("/webhook-config", func(ctx *fiber.Ctx) error {
		configMutex.RLock()
		defer configMutex.RUnlock()

		return ctx.JSON(WebhookResponse{
			Status:     "success",
			Message:    "Current webhook configuration",
			WebhookURL: currentConfig.WebhookURL,
		})
	})

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

