package main

import (
	"context"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Config holds the application's webhook configuration
type Config struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookRequest represents the incoming JSON request body structure
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	appConfig Config
	configMu  sync.Mutex // Ensures thread-safe access to the configuration
)

// ConfigureWebhook handles POST requests to validate and configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	req := new(WebhookRequest)
	if err := ctx.BodyParser(req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to parse request: " + err.Error(),
		})
	}

	// Validate required field presence
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is a required field",
		})
	}

	// Create context with 3-second timeout for validation request
	timeoutCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare GET request for validation
	httpReq, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid webhook URL format: " + err.Error(),
		})
	}

	// Execute validation request
	client := &http.Client{}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"success": false,
			"message": "Validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure resource cleanup

	// Save configuration in a thread-safe manner
	configMu.Lock()
	appConfig.WebhookURL = req.WebhookURL
	configMu.Unlock()

	// Return success response with validation details
	return ctx.JSON(fiber.Map{
		"success":            true,
		"message":            "Webhook configured successfully",
		"webhook_url":        appConfig.WebhookURL,
		"validation_response": resp.Status,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register webhook configuration route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Println("Server starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

