// isForbiddenIP checks if an IP address is in a restricted range (loopback, private, link-local, multicast)
func isForbiddenIP(ip net.IP) bool {
	return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsMulticast()
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and ensure it's an absolute URL
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Ensure the URL has a valid host
	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must include a host",
		})
	}

	// SSRF Protection: Resolve hostname and check for restricted IP ranges
	hostname, _, err := net.SplitHostPort(parsedURL.Host)
	if err != nil {
		// Host doesn't have a port, use the full host value
		hostname = parsedURL.Host
	}

	// Look up IP addresses for the hostname
	ips, err := net.LookupHost(hostname)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Could not resolve webhook URL: %v", err),
		})
	}

	// Check each resolved IP against restricted ranges
	for _, ipStr := range ips {
		ip := net.ParseIP(ipStr)
		if ip == nil {
			continue // Skip invalid IP addresses (unlikely from net.LookupHost)
		}
		if isForbiddenIP(ip) {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL points to a restricted internal or private network address",
			})
		}
	}

	// Create a custom HTTP client with strict timeout to prevent hanging requests
	client := &http.Client{
		Timeout: 3 * time.Second,
		// Disable redirects to prevent SSRF via open redirects
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to connect to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify the webhook returned a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the normalized webhook URL to the database
