			"success": false,
			"message": "Invalid URL format: " + err.Error(),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout for validation request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Prevent resource leaks

	// Optional: Uncomment to only accept URLs returning 2xx status codes
