package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming request body structure
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// savedWebhookURL stores the validated webhook URL (in-memory for demonstration purposes)
var savedWebhookURL string

// ConfigureWebhook handles POST requests to set and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Bind request body to struct
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body: " + err.Error(),
		})
	}

	// Validate required field presence
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure proper resource cleanup

	// Check for successful HTTP response status (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the validated webhook URL
	savedWebhookURL = req.WebhookURL

	// Return success response with saved configuration
	return ctx.JSON(fiber.Map{
		"status":       "success",
		"message":      "Webhook URL configured and validated successfully",
		"webhook_url":  savedWebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

