// isRestrictedIP checks if an IP address falls into a restricted range (private, loopback, link-local, etc.)
func isRestrictedIP(ip net.IP) bool {
	// Check loopback addresses
	if ip.IsLoopback() {
		return true
	}
	// Check link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Check private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		// 10.0.0.0/8
		case ip4[0] == 10:
			return true
		// 172.16.0.0/12 (172.16.x.x to 172.31.x.x)
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		// 192.168.0.0/16
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		// 100.64.0.0/10 (Carrier-grade NAT)
		case ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127:
			return true
		// 198.18.0.0/15 (Internal benchmarking)
		case ip4[0] == 198 && (ip4[1] == 18 || ip4[1] == 19):
			return true
		}
		return false
	}
	// Check restricted IPv6 ranges
	if ip6 := ip.To16(); ip6 != nil {
		switch {
