package main

import (
	"context"
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// AppConfig stores application-wide configuration
type AppConfig struct {
	WebhookURL string
}

// WebhookRequest represents the incoming POST request body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	appConfig   AppConfig
	configMutex sync.RWMutex
)

// ConfigureWebhook handles POST requests to configure and validate webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse and validate request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body: " + err.Error(),
		})
	}

	// Check if webhook URL is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate URL scheme (must be http or https)
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid webhook URL format: " + err.Error(),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL must use http or https scheme",
		})
	}

	// Create context with 3-second timeout for test request
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare test GET request
	testReq, err := http.NewRequestWithContext(ctxTimeout, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to create test request: " + err.Error(),
		})
	}

	// Send test request
	client := &http.Client{}
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Test request failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Check if test request returned a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save configuration with concurrency safety
	configMutex.Lock()
	appConfig.WebhookURL = req.WebhookURL
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook URL validated and saved successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

