// Global variables to store the saved webhook configuration with thread safety
var (
	savedWebhookURL string
	configMutex     sync.RWMutex
)

// WebhookConfigRequest represents the incoming JSON request structure
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse incoming JSON request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid request body: " + err.Error(),
		})
	}

	// 2. Validate required field presence
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is a required field",
		})
	}

	// 3. Validate URL format (scheme and host presence)
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid URL format: " + err.Error(),
		})
	}
	if parsedURL.Scheme == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "URL must include a scheme (http:// or https://)",
		})
	}
	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "URL must include a valid host",
		})
	}

	// 4. Create HTTP client with 3-second timeout for validation request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 5. Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"success": false,
			"error":   "failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// 6. Validate successful response status code (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL returned non-success status: " + resp.Status,
		})
	}

	// 7. Save configuration with thread safety
	configMutex.Lock()
	savedWebhookURL = req.WebhookURL
	configMutex.Unlock()

	// 8. Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "webhook URL validated and saved successfully",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register webhook configuration endpoint
