package main

import (
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest represents the incoming JSON request body
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// APIResponse represents the standard JSON response format
type APIResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	Error   string `json:"error,omitempty"`
}

// Global configuration storage with thread safety
var (
	currentWebhookURL string
	configMutex       sync.RWMutex
)

// ConfigureWebhook handles POST requests to set up and validate webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming request body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "Webhook URL is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "Invalid URL format: " + err.Error(),
		})
	}

	// Ensure URL uses valid HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout for validation
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "Validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Optional: Validate response status code is in 2xx range
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(APIResponse{
			Success: false,
			Error:   "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save configuration with thread safety
	configMutex.Lock()
	currentWebhookURL = parsedURL.String()
	configMutex.Unlock()

	// Return success response
	return ctx.JSON(APIResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register route for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

