package main

import (
	"log"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// AppConfig holds the application configuration
type AppConfig struct {
	WebhookURL string
}

var (
	config      AppConfig
	configMutex sync.RWMutex
)

// WebhookConfigRequest represents the incoming request body structure
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var reqBody WebhookConfigRequest
	if err := ctx.BodyParser(&reqBody); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate URL format first
	parsedURL, err := url.Parse(reqBody.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid webhook URL format: " + err.Error(),
		})
	}

	// Ensure URL uses HTTP or HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout for validation request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(reqBody.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks

	// Check if the webhook returned a successful status code (2xx)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the valid webhook URL to configuration (thread-safe)
	configMutex.Lock()
	config.WebhookURL = reqBody.WebhookURL
	configMutex.Unlock()

	// Return successful response
	return ctx.JSON(fiber.Map{
		"status":       "success",
		"message":      "Webhook URL configured and validated successfully",
		"webhook_url":  reqBody.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

