package main

import (
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body structure for webhook configuration
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// savedWebhookURL stores the configured webhook URL in memory
var savedWebhookURL string

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body into WebhookConfig struct
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to parse request body",
			"error":   err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid URL format",
			"error":   err.Error(),
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to reach webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the valid webhook configuration
	savedWebhookURL = config.WebhookURL

	// Return success response
	return ctx.JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured successfully",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register POST endpoint for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

