package main

import (
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request body
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

var currentWebhookConfig WebhookConfig

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfig

	// Parse incoming JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body: " + err.Error(),
		})
	}

	// Check if webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is a required field",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid URL format: " + err.Error(),
		})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "URL must use http or https scheme",
		})
	}

	// Create HTTP client with 3-second timeout
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to connect to webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check for successful HTTP response status
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the valid webhook configuration
	currentWebhookConfig = req

	// Return success response
	return ctx.JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configuration saved successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

