var privateIPRanges = []net.IPNet{
	// Loopback addresses
	{IP: net.IPv4(127, 0, 0, 0), Mask: net.CIDRMask(8, 32)},
	{IP: net.ParseIP("::1"), Mask: net.CIDRMask(128, 128)},
	// Private IPv4 ranges
	{IP: net.IPv4(10, 0, 0, 0), Mask: net.CIDRMask(8, 32)},
	{IP: net.IPv4(172, 16, 0, 0), Mask: net.CIDRMask(12, 32)},
	{IP: net.IPv4(192, 168, 0, 0), Mask: net.CIDRMask(16, 32)},
	// Private IPv6 ranges (Unique Local Addresses)
	{IP: net.ParseIP("fc00::"), Mask: net.CIDRMask(7, 128)},
	// Link-local addresses
	{IP: net.IPv4(169, 254, 0, 0), Mask: net.CIDRMask(16, 32)},
	{IP: net.ParseIP("fe80::"), Mask: net.CIDRMask(10, 128)},
	// Reserved addresses
	{IP: net.IPv4(0, 0, 0, 0), Mask: net.CIDRMask(8, 32)},
}

// isPrivateIP checks if an IP address falls into private, reserved, or loopback ranges
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	for _, r := range privateIPRanges {
		if r.Contains(ip) {
			return true
		}
	}
	return false
}

// validateRedirectURL checks if a redirected URL is safe (non-private, valid scheme)
func validateRedirectURL(redirectURL *url.URL) error {
	// Check scheme
	if redirectURL.Scheme != "http" && redirectURL.Scheme != "https" {
		return fmt.Errorf("redirect URL uses invalid scheme: %s", redirectURL.Scheme)
	}

	// Resolve host to IPs
	ips, err := net.LookupHost(redirectURL.Hostname())
	if err != nil {
		return fmt.Errorf("failed to resolve redirect host: %v", err)
	}

	// Check each IP for private ranges
	for _, ipStr := range ips {
		ip := net.ParseIP(ipStr)
		if isPrivateIP(ip) {
			return fmt.Errorf("redirect URL points to private IP: %s", ipStr)
		}
	}

	return nil
}

