		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			if err := validateRedirectURL(req.URL); err != nil {
				return err
			}
			// Allow up to 3 redirects to prevent infinite loops
			if len(via) >= 3 {
				return http.ErrUseLastResponse
			}
			return nil
		},
	}

	// Send test GET request to webhook URL
	resp, err := client.Get(parsedURL.String())
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
