package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

var savedWebhookURL string

type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the request body into the struct
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Invalid request body: " + err.Error(),
		})
	}

	// Check if webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save the configuration (in-memory storage for demonstration)
	savedWebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":      "success",
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the POST route for configuring webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

