package main

import (
	"fmt"
	"net/http"
	"net/url"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// AppConfig holds application configuration with thread-safe access
type AppConfig struct {
	mu         sync.RWMutex
	WebhookURL string
}

var config AppConfig

// WebhookConfigRequest represents the incoming POST request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// testWebhookURL validates the webhook URL with a GET request and 3-second timeout
func testWebhookURL(webhookURL string) error {
	// Parse and validate URL structure
	parsedURL, err := url.Parse(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Ensure URL uses HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Create HTTP client with strict 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request
	resp, err := client.Get(webhookURL)
	if err != nil {
		return fmt.Errorf("test request failed: %w", err)
	}
	defer resp.Body.Close()

	// Validate successful response status
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return fmt.Errorf("test request returned non-success status: %d", resp.StatusCode)
	}

	return nil
}

// ConfigureWebhook handles POST requests to configure and validate webhook URLs
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	// Check for missing webhook URL
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate the webhook URL
	if err := testWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"success": false,
			"message": fmt.Sprintf("URL validation failed: %v", err),
		})
	}

	// Save configuration thread-safely
	config.mu.Lock()
	config.WebhookURL = req.WebhookURL
	config.mu.Unlock()

	// Return success response
	return ctx.JSON(fiber.Map{
		"success":   true,
		"message":   "Webhook URL configured and validated successfully",
		"saved_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register API routes
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Get current webhook configuration
	app.Get("/current-webhook", func(ctx *fiber.Ctx) error {
		config.mu.RLock()
		defer config.mu.RUnlock()

		return ctx.JSON(fiber.Map{
			"success":     true,
			"webhook_url": config.WebhookURL,
		})
	})

	// Start server on port 3000
	fmt.Println("Server starting on :3000...")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Server startup failed: %v\n", err)
	}
}

