package main

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global thread-safe storage for webhook configuration
var (
	webhookConfig struct {
		sync.RWMutex
		URL string
	}
)

// WebhookConfigRequest represents the incoming POST request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookConfigResponse represents the standard JSON response
type WebhookConfigResponse struct {
	Success    bool   `json:"success"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate required field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create context with 3-second timeout for test request
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Prepare test GET request
	testReq, err := http.NewRequestWithContext(ctxTimeout, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid URL format: " + err.Error(),
		})
	}

	// Send test request to validate webhook URL
	client := &http.Client{}
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Validate response status code (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(WebhookConfigResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save configuration with thread-safe access
	webhookConfig.Lock()
	webhookConfig.URL = req.WebhookURL
	webhookConfig.Unlock()

	// Return success response
	return ctx.JSON(WebhookConfigResponse{
		Success:    true,
		Message:    "Webhook configuration updated successfully",
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register API endpoints
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional endpoint to retrieve current configuration
	app.Get("/webhook-config", func(ctx *fiber.Ctx) error {
		webhookConfig.RLock()
		currentURL := webhookConfig.URL
		webhookConfig.RUnlock()

		return ctx.JSON(fiber.Map{
			"current_webhook_url": currentURL,
		})
	})

	// Start server on port 3000
	fmt.Println("Server starting on http://localhost:3000")
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}

