var (
	savedWebhookURL string
	mu              sync.RWMutex
)

// WebhookConfigRequest represents the incoming request body for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookConfigResponse represents the response sent back after configuration attempt
type WebhookConfigResponse struct {
	Success    bool   `json:"success"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
	StatusCode int    `json:"status_code,omitempty"`
}

// ConfigureWebhook handles POST requests to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest

	// Parse and validate incoming request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Check if webhook URL is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Invalid URL format: " + err.Error(),
		})
	}

	// Ensure URL uses HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "URL must use http or https scheme",
		})
	}

	// Ensure URL has a valid host
	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookConfigResponse{
			Success: false,
			Message: "URL must include a valid host",
		})
	}

	// Create HTTP client with 3-second timeout for test request
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(WebhookConfigResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Prepare status message based on response code
	var statusMsg string
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		statusMsg = "Test request succeeded with status: " + resp.Status
	} else {
		statusMsg = "Test request received non-success status: " + resp.Status
	}

	// Save configuration with thread-safe access
	mu.Lock()
	savedWebhookURL = req.WebhookURL
	mu.Unlock()

	// Return success response
	return ctx.JSON(WebhookConfigResponse{
		Success:    true,
		Message:    "Webhook configuration saved successfully. " + statusMsg,
		WebhookURL: req.WebhookURL,
		StatusCode: resp.StatusCode,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register webhook configuration route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

